        {
          "@type": "Question",
          "name": "What is the difference between stamp duty and registration fees in Maharashtra?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Stamp duty is a tax on the instrument itself, levied under the Maharashtra Stamp Act 1958, while the registration fee is a separate charge for recording that instrument with the sub-registrar under the Registration Act 1908. Both are payable on a sale deed, and the registration fee is generally 1 percent of the agreement value subject to a monetary ceiling."
          }
        },
        {
          "@type": "Question",
          "name": "What happens if a document is not properly stamped in Maharashtra?",
